// Reshape input to match original node expectations
// Original nodes expect: .body (webhook metadata), .data (transcript text)
const input = $input.first().json;
const transcript = input.transcript || {};
return [{json: {
  body: {
    meeting_name: input.meeting_name || '',
    participants: input.participants || '',
    date: input.date || '',
    start_time: input.start_time || '',
    end_time: input.end_time || '',
    context: input.context || '',
    chat_id: input.chat_id || '',
    file_id: input.file_id || '',
    bot_token: input.bot_token || '',
    queue_id: input.queue_id || ''
  },
  data: transcript.data || transcript.text || '',
  segments: transcript.segments || [],
  language: transcript.language || 'fi',
  // Keep raw transcript for Return Results
  _transcript: transcript,
  _meeting_name: input.meeting_name,
  _participants: input.participants,
  _date: input.date,
  _start_time: input.start_time,
  _end_time: input.end_time
}}];

function estimateCtx(promptChars, responseTokens) {
  responseTokens = responseTokens || 2048;
  const promptTokens = Math.ceil(promptChars / 3.5);
  const raw = promptTokens + responseTokens;
  const rounded = Math.ceil(raw / 1024) * 1024;
  return Math.max(2048, Math.min(rounded, 49152));
}
// ── Free VRAM: unload idle models before LLM-heavy pipeline ──
// MUST use /api/chat (not /api/generate) to override keep_alive:-1 set by telegram-agent
try {
    await this.helpers.httpRequest({
        method: 'POST', url: 'http://host.docker.internal:11434/api/chat',
        body: {model: 'qwen2.5vl:7b', messages: [{role: 'user', content: 'x'}], keep_alive: 0, stream: false}, json: true
    });
} catch(e) { /* model may not be loaded — ignore */ }
try {
    await this.helpers.httpRequest({
        method: 'POST', url: 'http://host.docker.internal:11434/api/chat',
        body: {model: 'nemotron-mini', messages: [{role: 'user', content: 'x'}], keep_alive: 0, stream: false}, json: true
    });
} catch(e) { /* model may not be loaded — ignore */ }
try {
    await this.helpers.httpRequest({
        method: 'POST', url: 'http://host.docker.internal:11434/api/embed',
        body: {model: 'nomic-embed-text-v2-moe', input: 'x', keep_alive: 0}, json: true
    });
} catch(e) { /* embedding model — ignore */ }

const webhookBody = $('Set Metadata').first().json.body;
const participants = webhookBody.participants;
const participantStr = Array.isArray(participants) && participants.length
    ? participants.join(', ') : 'unknown';
const rawTranscript = $('Set Metadata').first().json.data || '';

// Full transcript for speaker ID — even 83-min meetings (72k chars) fit in 32k tokens
// Prompt eval dominates (~220s), generation is tiny (~50 tokens)
const MAX_CHARS = 75000;
const transcript = rawTranscript.length > MAX_CHARS
    ? rawTranscript.substring(0, MAX_CHARS) + '\n\n[... truncated ...]'
    : rawTranscript;

// Count distinct SPEAKER_XX labels vs participant count
const speakerLabels = [...new Set(
    (rawTranscript.match(/\[SPEAKER_\d+\]/g) || []).map(m => m.slice(1, -1))
)].sort();
const participantList = participantStr.split(',').map(p => p.trim()).filter(Boolean).sort();
const speakerCount = speakerLabels.length;
const participantCount = participantList.length;

// Build allowed values list for strict output constraint
const allowedValuesList = participantList.map(p => `- "${p}"`).join('\n');

let mismatchWarning = '';
if (speakerCount > 0 && speakerCount !== participantCount) {
    if (speakerCount > participantCount) {
        mismatchWarning = `\n\nNOTE: Diarization detected ${speakerCount} speaker labels but there are only ${participantCount} participants. This is OVER-SEGMENTATION — multiple labels belong to the same person. Map multiple SPEAKER_XX labels to the same participant when evidence supports it.`;
    } else {
        mismatchWarning = `\n\nWARNING: Diarization detected only ${speakerCount} speaker(s) but there are ${participantCount} participants. Some speakers are likely MERGED into one cluster.\n- Only map a SPEAKER label if there is STRONG evidence (self-introduction, direct address by name).\n- If a label likely contains multiple people's speech, keep the original SPEAKER_XX label.`;
    }
}

const systemPrompt = `You map SPEAKER labels to participant names in a meeting transcript.

KNOWN PARTICIPANTS: ${participantStr}

ALLOWED OUTPUT VALUES (use EXACTLY these strings or keep the SPEAKER_XX label):
${allowedValuesList}
- Keep original label (e.g. "SPEAKER_00") if you cannot identify the speaker.

RULES:
1. Speakers already labeled with a real name (e.g. [Petri], [Mikko]) are biometrically verified. Do NOT change them. Map them to themselves.
2. Only identify unresolved labels: [SPEAKER_00], [SPEAKER_01], [Unknown], etc.
3. Output value MUST be one of the allowed values above. No other values permitted.
4. Use evidence: self-introductions, direct address by name, topic expertise, response patterns.
5. Do NOT assume any participant is SPEAKER_00 based on their position in the list. The list is alphabetically sorted and has NO correlation with speaker order.
6. If unsure, keep the SPEAKER_XX label — never guess.
7. Output ONLY valid JSON. No explanation, no markdown.${mismatchWarning}`;

// Build JSON template with exact speaker labels from transcript
const templateObj = {};
for (const label of speakerLabels) {
    templateObj[label] = '?';
}
const templateStr = JSON.stringify({speaker_map: templateObj}, null, 2);

const userMsg = `Transcript:\n${transcript}\n\nReplace each "?" with EXACTLY one of: ${participantList.map(p => `"${p}"`).join(', ')}, or the original SPEAKER_XX label.\n\n${templateStr}`;

return [{ json: {
    body: JSON.stringify({
        model: 'qwen3.5:27b-32k',
        stream: false,
        think: false,
        num_ctx: estimateCtx((systemPrompt || "").length + (userMsg || "").length),
        system: systemPrompt,
        prompt: userMsg
    }),
    participantStr: participantStr,
    rawTranscript: rawTranscript
} }];

function estimateCtx(promptChars, responseTokens) {
  responseTokens = responseTokens || 2048;
  const promptTokens = Math.ceil(promptChars / 3.5);
  const raw = promptTokens + responseTokens;
  const rounded = Math.ceil(raw / 1024) * 1024;
  return Math.max(2048, Math.min(rounded, 49152));
}
const rawTranscript = $('Set Metadata').first().json.data || '';

// ── safeParseJSON: strips think tokens, fences, preamble text ──
function safeParseJSON(raw) {
    let s = (raw || '').trim();
    // Strip <think>...</think> blocks (qwen reasoning tokens)
    s = s.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
    // Strip markdown code fences
    s = s.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?\s*```\s*$/i, '');
    s = s.trim();
    // Find first { to last }
    const first = s.indexOf('{');
    const last = s.lastIndexOf('}');
    if (first === -1 || last === -1 || last <= first) {
        return { ok: false, data: null, error: 'No JSON object found', raw: raw };
    }
    s = s.substring(first, last + 1);
    try {
        return { ok: true, data: JSON.parse(s), error: null };
    } catch(e) {
        return { ok: false, data: null, error: e.message, raw: raw };
    }
}

// Parse speaker map from previous pass
let speakerMap = {};
const speakerResp = $input.first().json.response || '';
const parsed = safeParseJSON(speakerResp);
if (parsed.ok) {
    speakerMap = parsed.data.speaker_map || {};
} else if (speakerResp.trim()) {
    console.log('Speaker map parse failed: ' + (parsed.error || 'unknown'));
    console.log('Raw response: ' + speakerResp.substring(0, 500));
}

// Apply speaker names to transcript for better topic identification
let resolvedTranscript = rawTranscript;
for (const [label, name] of Object.entries(speakerMap)) {
    resolvedTranscript = resolvedTranscript.replaceAll('[' + label + ']', '[' + name + ']');
}

// Full transcript — same budget as speaker ID pass
const MAX_CHARS = 75000;
const transcript = resolvedTranscript.length > MAX_CHARS
    ? resolvedTranscript.substring(0, MAX_CHARS) + '\n\n[... truncated ...]'
    : resolvedTranscript;

const systemPrompt = `You identify discussion topics in a meeting transcript.

For each topic, provide:
- A descriptive name in ENGLISH (3-8 words) that captures the SUBJECT MATTER discussed. Example: "Simulator Architecture Review", "Resource Allocation by Factory", "SKU Data Import Strategy". NEVER use generic names like "Topic 1", "Segment 2", or "General Discussion". NEVER use Finnish or other non-English names.
- Start and end timestamps in seconds
- A one-sentence English summary

CRITICAL RULES:
- Output ONLY valid JSON. No markdown, no explanation.
- Topic names MUST be in English.
- CONSOLIDATE related discussions into one topic.
- Chronological order, no gaps.
- Merge topics shorter than 60 seconds into adjacent ones.
- 3-6 well-consolidated topics.
- The LAST topic's "end" value MUST be the number 999999, NOT the actual last timestamp. This is a sentinel value used by downstream code.`;

const userMsg = `Transcript:\n${transcript}\n\nREMINDER: Topic names and summaries MUST be in ENGLISH, not Finnish. Translate any Finnish concepts to English.\n\nNow output the JSON. The last topic MUST end with 999999 (do NOT use the real timestamp like 3400 or 3482 — use exactly 999999):\n{"topics": [{"name": "English Topic Name Here", "start": 0.0, "end": ..., "summary": "English summary here"}, ..., {"name": "English Topic Name", "start": ..., "end": 999999, "summary": "English summary"}]}`;

return [{ json: {
    body: JSON.stringify({
        model: 'qwen3.5:27b-32k',
        stream: false,
        think: false,
        num_ctx: estimateCtx((systemPrompt || "").length + (userMsg || "").length),
        system: systemPrompt,
        prompt: userMsg
    }),
    speakerMapRaw: speakerResp,
    speakerMap: speakerMap
} }];

const webhookBody = $('Set Metadata').first().json.body;
const date = webhookBody.date || new Date().toISOString().split('T')[0];
const participants = webhookBody.participants;
const participantStr = Array.isArray(participants) && participants.length
    ? participants.join(', ') : 'unknown';
const meetingName = webhookBody.meeting_name || '';
const startTime = webhookBody.start_time || '';
const endTime = webhookBody.end_time || '';
const context = webhookBody.context || '';
const transcriptFull = $('Set Metadata').first().json.data;

// ── safeParseJSON ──
function safeParseJSON(raw) {
    let s = (raw || '').trim();
    s = s.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
    s = s.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?\s*```\s*$/i, '');
    s = s.trim();
    const first = s.indexOf('{');
    const last = s.lastIndexOf('}');
    if (first === -1 || last === -1 || last <= first) {
        return { ok: false, data: null, error: 'No JSON object found', raw: raw };
    }
    s = s.substring(first, last + 1);
    try {
        return { ok: true, data: JSON.parse(s), error: null };
    } catch(e) {
        return { ok: false, data: null, error: e.message, raw: raw };
    }
}

// ── Deterministic topic segmentation fallback ──
// Segments by speaker turn patterns and time distribution
function deterministicTopics(transcript) {
    const lines = transcript.split('\n');
    const tsRegex = /\[(\d[\d:.]+)\s*(?:-->|->|\u2013|\u2014|-)\s*(\d[\d:.]+)\]/;
    const spkRegex = /\[([A-Z_]+\d*|[^\]]+)\]/;

    function timeToSec(t) {
        const p = t.trim().split(':');
        if (p.length === 3) return parseFloat(p[0])*3600 + parseFloat(p[1])*60 + parseFloat(p[2]);
        if (p.length === 2) return parseFloat(p[0])*60 + parseFloat(p[1]);
        return parseFloat(t) || 0;
    }

    // Parse all timestamped lines
    const entries = [];
    for (const line of lines) {
        const tsMatch = line.match(tsRegex);
        if (tsMatch) {
            const start = timeToSec(tsMatch[1]);
            const end = timeToSec(tsMatch[2]);
            const spkMatch = line.match(/\[(SPEAKER_\d+|[A-Z][a-zÀ-ÿ]+ [A-Z][a-zÀ-ÿ]+)\]/);
            const speaker = spkMatch ? spkMatch[1] : '';
            const text = line.replace(tsRegex, '').replace(/\[[^\]]*\]/g, '').trim();
            // Skip artifact lines (repeated single words like "Kiitos")
            if (text.length < 15 && /^(Kiitos[.!]*\s*)+$/i.test(text)) continue;
            entries.push({ start, end, speaker, text, line });
        }
    }

    if (entries.length === 0) return null;

    const totalStart = entries[0].start;
    const totalEnd = entries[entries.length - 1].end;
    const duration = totalEnd - totalStart;

    // Target 4-6 topics for a typical 30-60 min meeting
    const targetTopics = Math.max(3, Math.min(7, Math.round(duration / 300)));
    const targetLen = duration / targetTopics;

    // Find natural boundaries: score each entry as a potential boundary
    // Good boundaries: speaker changes after a gap, or after a long monologue
    const boundaries = [totalStart];
    let lastBoundary = totalStart;

    for (let i = 1; i < entries.length; i++) {
        const timeSinceBoundary = entries[i].start - lastBoundary;
        if (timeSinceBoundary < targetLen * 0.6) continue; // Too soon

        const gap = entries[i].start - entries[i-1].end;
        const speakerChange = entries[i].speaker !== entries[i-1].speaker;

        // Score this as a boundary point
        let score = 0;
        if (gap > 2) score += 2;
        if (gap > 5) score += 2;
        if (speakerChange) score += 3;
        if (timeSinceBoundary > targetLen * 0.8) score += 3;
        if (timeSinceBoundary > targetLen * 1.2) score += 5; // Overdue

        if (score >= 5) {
            boundaries.push(entries[i].start);
            lastBoundary = entries[i].start;
        }
    }
    boundaries.push(999999);

    // Build topics from boundaries
    const topics = [];
    for (let i = 0; i < boundaries.length - 1; i++) {
        const tStart = boundaries[i];
        const tEnd = boundaries[i + 1];
        // Get representative text for naming
        const topicEntries = entries.filter(e => e.start >= tStart && e.start < tEnd);
        const sampleText = topicEntries.slice(0, 5).map(e => e.text).join(' ');
        // Simple name from first substantial line
        const firstLine = topicEntries.find(e => e.text.length > 20);
        const name = firstLine
            ? firstLine.text.substring(0, 50).replace(/[.!?,;:]+$/, '') + '...'
            : `Topic ${i + 1}`;

        topics.push({
            name: name,
            start: tStart,
            end: tEnd === 999999 ? 999999 : tEnd,
            summary: name
        });
    }

    return topics.length >= 2 ? topics : null;
}

// Speaker map from pass 1
const speakerMapData = $('Build Topic Segmentation Prompt').first().json.speakerMap || {};
const rawSpeakerMap = speakerMapData;

// Parse topics from pass 2 LLM response
let topics = [];
let topicsFallback = false;
const rawTopicResp = $input.first().json.response || '';
const parsed = safeParseJSON(rawTopicResp);
if (parsed.ok && parsed.data.topics && parsed.data.topics.length >= 2) {
    topics = parsed.data.topics;
} else {
    // LLM failed or returned single topic — try deterministic segmentation
    console.log('LLM topic segmentation failed or returned <2 topics, using deterministic fallback');
    if (parsed.error) console.log('Parse error: ' + parsed.error);
    const detTopics = deterministicTopics(transcriptFull);
    if (detTopics) {
        topics = detTopics;
        topicsFallback = true;
    } else {
        topics = [{name: 'Full Meeting', start: 0, end: 999999, summary: 'Complete meeting discussion'}];
        topicsFallback = true;
    }
}

// Fix sentinel value leaking as topic name
for (let i = 0; i < topics.length; i++) {
    if (/^\d+$/.test(topics[i].name) || topics[i].name === '999999') {
        const fallbackName = (topics[i].summary && topics[i].summary.length > 5 && !/^\d+$/.test(topics[i].summary))
            ? topics[i].summary.substring(0, 60)
            : 'Closing Discussion';
        console.log('Fixed sentinel topic name "' + topics[i].name + '" → "' + fallbackName + '"');
        topics[i].name = fallbackName;
    }
}

// ── Fix Finnish topic names: detect non-ASCII and translate common patterns ──
// Finnish chars: ä ö å Ä Ö Å and common Finnish suffixes
const FINNISH_RE = /[äöåÄÖÅ]|\b(?:ja|tai|sekä|kanssa|kohti|katsaus|hallinta|suunnitelma|päätös|loppu|keskustelu|poistaminen|lisääminen|muokkaaminen|päivitys|käyttöönotto)\b/;
for (let i = 0; i < topics.length; i++) {
    if (FINNISH_RE.test(topics[i].name)) {
        // Topic name is in Finnish — use the LLM summary if it's in English, else generic
        if (topics[i].summary && !FINNISH_RE.test(topics[i].summary) && topics[i].summary.length > 5) {
            // Summary is English — use it as the name (truncated)
            let englishName = topics[i].summary;
            if (englishName.length > 60) englishName = englishName.substring(0, 57) + '...';
            // Capitalize first letter of each major word
            englishName = englishName.replace(/\b[a-z]/g, c => c.toUpperCase());
            topics[i].name = englishName;
        } else {
            // Both name and summary are Finnish — mark for downstream
            topics[i].name = 'Topic ' + (i + 1) + ' (translation needed)';
        }
        console.log('Fixed Finnish topic name at index ' + i + ': ' + topics[i].name);
    }
}

// Validate speaker map against known participants — post-LLM safety net
// Normalizes partial matches (e.g. "Jaakko" → "Hahtola Jaakko") and rejects unknowns
const knownLower = participantStr.toLowerCase().split(',').map(p => p.trim()).filter(Boolean);
const participantListOrig = participantStr.split(',').map(p => p.trim()).filter(Boolean);

// Build lookup: each name part → index into participant list
const partToIdx = {};
for (let idx = 0; idx < knownLower.length; idx++) {
    partToIdx[knownLower[idx]] = idx; // exact full name
    for (const part of knownLower[idx].split(' ')) {
        if (part.length > 2) partToIdx[part] = idx;
    }
}

const speakerMap = {};
for (const [label, name] of Object.entries(rawSpeakerMap)) {
    // Biometrically verified labels pass through
    if (!label.startsWith('SPEAKER_') && label !== 'Unknown') {
        speakerMap[label] = name;
        continue;
    }
    const nameLower = name.toLowerCase().trim();
    // Exact match to a known participant?
    if (partToIdx[nameLower] !== undefined) {
        speakerMap[label] = participantListOrig[partToIdx[nameLower]];
        continue;
    }
    // Partial match: check each word
    let matched = false;
    for (const word of nameLower.split(' ')) {
        const clean = word.replace(/[.,;:!?]/g, '');
        if (clean.length > 2 && partToIdx[clean] !== undefined) {
            speakerMap[label] = participantListOrig[partToIdx[clean]];
            matched = true;
            break;
        }
    }
    // No match — revert to original label
    if (!matched) speakerMap[label] = label;
}

const mapEntries = Object.entries(speakerMap).map(([k, v]) => `${k} = ${v}`).join(', ');

// Detect duplicate mappings (multiple SPEAKER_XX → same person = over-segmentation)
const nameToLabels = {};
for (const [label, name] of Object.entries(speakerMap)) {
    if (!label.startsWith('SPEAKER_')) continue;
    if (!nameToLabels[name]) nameToLabels[name] = [];
    nameToLabels[name].push(label);
}
const dupes = Object.entries(nameToLabels)
    .filter(([name, labels]) => labels.length > 1 && !name.startsWith('SPEAKER_'))
    .map(([name, labels]) => `${name} \u2190 ${labels.join('+')}`)
    .join('; ');
const dedupNote = dupes ? ` | Merged clusters: ${dupes}` : '';

const speakerComment = `<!-- Speaker map: ${mapEntries}${dedupNote} -->`;

// Apply speaker names to transcript
let resolvedTranscript = transcriptFull;
for (const [label, name] of Object.entries(speakerMap)) {
    resolvedTranscript = resolvedTranscript.replaceAll(`[${label}]`, `[${name}]`);
}

// Slice transcript by timestamps
const lines = resolvedTranscript.split('\n');

function timeToSeconds(timeStr) {
    const parts = timeStr.trim().split(':');
    if (parts.length === 3) return parseFloat(parts[0])*3600 + parseFloat(parts[1])*60 + parseFloat(parts[2]);
    if (parts.length === 2) return parseFloat(parts[0])*60 + parseFloat(parts[1]);
    return parseFloat(timeStr) || 0;
}

const lineTimestamps = [];
let lastTimestamp = 0;
const tsRegex = /\[(\d[\d:.]+)\s*(?:-->|->|\u2013|\u2014|-)\s*(\d[\d:.]+)\]/;
for (const line of lines) {
    const match = line.match(tsRegex);
    if (match) lastTimestamp = timeToSeconds(match[1]);
    lineTimestamps.push({line, timestamp: lastTimestamp});
}

const topicItems = [];
for (let i = 0; i < topics.length; i++) {
    const topic = topics[i];
    const tStart = topic.start || 0;
    const tEnd = topic.end || 999999;
    const topicLines = lineTimestamps
        .filter(lt => lt.timestamp >= tStart && lt.timestamp <= tEnd)
        .map(lt => lt.line);
    const topicTranscript = topicLines.join('\n');

    topicItems.push({
        json: {
            topicIndex: i,
            topicName: topic.name,
            topicSummary: topic.summary || '',
            topicTranscript: topicTranscript,
            totalTopics: topics.length,
            speakerComment: speakerComment,
            speakerMap: speakerMap,
            date: date,
            meetingName: meetingName,
            startTime: startTime,
            endTime: endTime,
            participantStr: participantStr,
            context: context,
            topicsFallback: topicsFallback,
        }
    });
}

// Catch orphaned lines past last topic
if (topicItems.length > 0) {
    const coveredMax = Math.max(...topics.map(t => t.end || 0));
    const orphanLines = lineTimestamps
        .filter(lt => lt.timestamp > coveredMax)
        .map(lt => lt.line)
        .filter(l => l.trim());
    if (orphanLines.length > 0) {
        const lastItem = topicItems[topicItems.length - 1];
        lastItem.json.topicTranscript += '\n' + orphanLines.join('\n');
    }
}

if (topicItems.length === 0) {
    topicItems.push({
        json: {
            topicIndex: 0,
            topicName: 'Full Meeting',
            topicSummary: 'Complete meeting discussion',
            topicTranscript: resolvedTranscript,
            totalTopics: 1,
            speakerComment: speakerComment,
            speakerMap: speakerMap,
            date: date,
            meetingName: meetingName,
            startTime: startTime,
            endTime: endTime,
            participantStr: participantStr,
            context: context,
            topicsFallback: true,
        }
    });
}

return topicItems;

function estimateCtx(promptChars, responseTokens) {
  responseTokens = responseTokens || 2048;
  const promptTokens = Math.ceil(promptChars / 3.5);
  const raw = promptTokens + responseTokens;
  const rounded = Math.ceil(raw / 1024) * 1024;
  return Math.max(2048, Math.min(rounded, 49152));
}
const item = $input.item.json;
const topicName = item.topicName;

const systemPrompt = `You analyze a SINGLE TOPIC from a meeting transcript.
Output must be in this exact markdown format:

### ${topicName}
<one sentence summarizing the outcome — REPLACE this instruction with your actual summary, never echo instructions>

**Key Points:**
Write 3-5 bullets describing WHAT happened, WHAT was decided, or WHAT the status is. Write impersonally — like a board meeting summary.
GOOD: "The R7 design model is complete but investment numbers remain pending due to vendor queries."
GOOD: "Production targets were met despite mold delays; one batch required rework due to incorrect filling."
BAD: "Hahtola Jaakko noted that the R7 design model is complete."
BAD: "Syvänen Sirpa confirmed that production targets were met."
Name a speaker ONLY if they own an action or made a binding decision (max 1-2 names per topic).
Do NOT include timestamps, speaker labels, or action items in key points.

**Outcome:** Write exactly one of: "Decision made", "Action items created", "Information shared", or "No outcome". Nothing else.

IF a concrete decision was made in this topic, include:
#### DECISION
**What:** describe the decision concisely
If NO decision was made, OMIT the #### DECISION section entirely. Do NOT write "No decision" or leave it empty.

IF concrete action items or follow-ups were agreed, include:
#### ACTION ITEMS
- [ ] ***Action Point:*** <emoji> **What:** <task> **Who:** [[Lastname Firstname]] **When:** YYYY-MM-DD
Every action item line MUST start with exactly: - [ ] ***Action Point:*** <emoji>
If NO action items exist, OMIT the #### ACTION ITEMS section entirely. Do NOT write "No action items" or leave it empty.

RULES:
- Use complexity emoji inline on action items: 🟩 (<1h) 🟨 (1-4h) 🟧 (1-3d) 🟥 (>3d). Do NOT output a legend block.
- Names MUST be [[Lastname Firstname]] order (family name first). If BOTH first AND last name are known, always write [[Lastname Firstname]]. First-name-only stays plain text, no wikilink.
- NAME SPELLING: Use exact name spellings from the participant list but ALWAYS reorder to Lastname Firstname. For example, if participant list says "Johanna Aivio", write [[Aivio Johanna]].
- Do NOT invent facts. Only use what is explicitly in the transcript.
