// Replace "Firstname GarbledWord" with canonical name in plain text (not wikilinks)
for (const [firstName, canonical] of Object.entries(firstNamePatterns)) {
    const escapedFirst = firstName.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
