notesBody = notesBody.replace(/IF NO action items exist[\s\S]*?Do NOT write "No action items"[^\n]*\n?/gi, '');
notesBody = notesBody.replace(/IF concrete action items or follow-ups[\s\S]*?<emoji>[^\n]*\n?/gi, '');

