notesBody = notesBody.replace(/^IF concrete action items or follow-ups were agreed[^\n]*include:?\s*$/gm, '');
notesBody = notesBody.replace(/^IF concrete action items were agreed[^\n]*$/gm, '');
notesBody = notesBody.replace(/^IF NO decision was made[^\n]*$/gm, '');
notesBody = notesBody.replace(/^IF NO action items[^\n]*$/gm, '');
notesBody = notesBody.replace(/^OMIT the ####[^\n]*$/gm, '');
